sql:
SELECT 
  (SELECT COUNT(*) FROM users WHERE status = 'active') AS active_users,
  (SELECT COUNT(*) FROM roles) AS total_roles;

external_knowledge:
- 'academic gardens' is a metaphor for colleges or universities;
- 'sowing the seeds' implies offering courses;
- 'fertile plots' refers to specific seat categories within the courses;
- 'inquisitive minds' are the students applying for admission;
- 'stewards' are the individuals managing these institutions, whose roles are indicated by 'role_name';
- 'success rate' corresponds to the 'acceptance_rate', which is greater than 80%.

sql:
SELECT college_id, COUNT(course_id) AS num_courses
FROM college_courses
GROUP BY college_id;

SELECT admission_requirements
FROM college_courses
WHERE college_id = 1 AND course_id = 1;

SELECT admission_count, average_gpa, average_test_score
FROM admission_statistics
WHERE college_id = 0;

SELECT course_name
FROM courses
WHERE duration < 4 AND fees > 100000;

SELECT AVG(CAST(average_gpa AS FLOAT)) AS average_gpa
FROM admission_statistics
WHERE admission_year = 2020;
